import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"项目简介","description":"华南理工大学学生共同维护的非官方学习生活信息手册","frontmatter":{"lang":"zh-CN","title":"项目简介","description":"华南理工大学学生共同维护的非官方学习生活信息手册"},"headers":[],"relativePath":"en/introduction.md","filePath":"en/introduction.md","lastUpdated":1784220723000}`),a={name:`en/introduction.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/introduction.md for this page in Markdown format</div><h1 id="这本手册是什么" tabindex="-1">这本手册是什么 <a class="header-anchor" href="#这本手册是什么" aria-label="Permalink to “这本手册是什么”">​</a></h1><p>Survive in SCUT（华南理工大学生存手册）是一份由学生共同编写、面向华工学习与生活场景的非官方信息指南。它整理分散在通知、制度、经验和校园日常中的信息，降低新生和在校生反复搜索、试错与踩坑的成本。</p><p>这本手册提供的是<strong>信息与经验</strong>，不是学校文件，也不替你做决定。涉及学籍、培养方案、奖助、医疗、安全等事项时，应以学校及相关部门发布的最新规定为准。</p><h2 id="适合谁" tabindex="-1">适合谁 <a class="header-anchor" href="#适合谁" aria-label="Permalink to “适合谁”">​</a></h2><ul><li>准备报考或即将入学，想提前了解真实校园生活的人；</li><li>在校期间需要查询课程、设施、生活服务、升学与健康信息的人；</li><li>愿意补充亲历经验、核对规则或修正过期信息的贡献者。</li></ul><p>不同学院、专业、年级和校区的执行情况可能不同。个人经验可以帮你缩小信息差，但不能直接替代适用于你本人的正式通知。</p><h2 id="怎么使用" tabindex="-1">怎么使用 <a class="header-anchor" href="#怎么使用" aria-label="Permalink to “怎么使用”">​</a></h2><ol><li><strong>先搜索具体问题。</strong> 用页面顶部的搜索框输入课程名、校区、业务或关键词，不必从头通读。</li><li><strong>检查时间与来源。</strong> 优先参考有明确年份、适用范围和来源的内容；缺少这些信息时，提高警惕。</li><li><strong>用官方信息完成确认。</strong> 遇到报名条件、截止时间、材料清单、成绩计算等会直接影响结果的事项，再到学校官网、教务系统或负责部门核验。</li><li><strong>把经验当作选项。</strong> 手册告诉你别人如何处理问题，最终选择仍取决于你的目标、成本和风险承受能力。</li></ol><h2 id="哪些内容可能过期" tabindex="-1">哪些内容可能过期 <a class="header-anchor" href="#哪些内容可能过期" aria-label="Permalink to “哪些内容可能过期”">​</a></h2><p>以下信息变化较快，不应脱离发布日期单独使用：</p><ul><li>新生报到时间、入口、材料与接站安排；</li><li>校巴、校门、场馆、食堂和服务网点的开放时间；</li><li>转专业、推免、评奖评优、综测与培养方案规则；</li><li>校医院就诊、转诊、医保与报销流程；</li><li>校园周边商户、价格、交通线路和联系方式。</li></ul><p>如果页面没有标明核对时间，默认它只代表编写时的情况。发现内容与现实不符时，以最新官方通知为准，并欢迎立即修正。</p><h2 id="如何参与共建" tabindex="-1">如何参与共建 <a class="header-anchor" href="#如何参与共建" aria-label="Permalink to “如何参与共建”">​</a></h2><p>你不需要掌握整个项目才可以贡献。一次错别字修正、一条来源补充、一段亲历流程或一项过期信息标记，都能减少后来者的试错成本。</p><ul><li>在页面底部点击“编辑此页”，直接提交修改；</li><li>在 GitHub 提交 Issue，说明问题、适用范围和信息来源；</li><li>阅读<a href="/en/others/contributing.html">贡献指南</a>与<a href="/en/others/todo.html">TODO 汇总</a>，认领尚未完善的内容。</li></ul><p>贡献事实性内容时，请尽量写清<strong>适用校区、学院或人群、核对日期和信息来源</strong>。手册的价值不在于说得像权威，而在于让信息可以被核验、修正和继续传递。</p>`,17)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};